// XOR a remote/physical adb endpoint (adb) — never both, never neither. Shared
// #Step from _common.cue.
//
// CLOSED: the base struct (no trailing `...`) models every authored key, so an
// unknown key is still a typo. The box⊻adb exactly-one mutual-exclusion is
// enforced in GO (validateAndroidDevices in unified.go, the load-time sibling of
// validateCheckBeds) — NOT by a trailing `& ({box:_} | {adb:_})` disjunction:
// `cue exp gengotypes` collapses an entity-level top-level disjunction to an
// EMPTY `struct{}`, which would make spec.Android useless as a drop-in for
// AndroidSpec. The plain closed struct below generates the full field set, and
// the Go rule restores the exactly-one-of-box/adb XOR.
type Android struct {
	Serial string `yaml:"serial,omitempty" json:"serial,omitempty"`

	Device string `yaml:"device,omitempty" json:"device,omitempty"`

	ApiLevel int `yaml:"api_level,omitempty" json:"api_level,omitempty"`

	GoogleAccount *GoogleAccount `yaml:"google_account,omitempty" json:"google_account,omitempty"`

	Plan []Step `yaml:"plan,omitempty" json:"plan,omitempty"`

	// Device source — exactly one of box/adb (enforced in Go, see header).
	Box string `yaml:"box,omitempty" json:"box,omitempty"`

	Adb *AdbEndpoint `yaml:"adb,omitempty" json:"adb,omitempty"`
}

type GoogleAccount struct {
	EmailSecret string `yaml:"email_secret,omitempty" json:"email_secret,omitempty"`

	TokenSecret string `yaml:"token_secret,omitempty" json:"token_secret,omitempty"`
}

// adb endpoint host is "host:port" but MAY carry a ${HOST_PORT:N} var-ref
// (resolved at deploy time), so only non-emptiness is enforced.
type AdbEndpoint struct {
	Host string `yaml:"host,omitempty" json:"host"`
}

// #HolderAddr is the self-contained address of a deployment (holder or claimant) — enough for the
// host seams to probe/stop/start it WITHOUT re-reading config, so a lease loaded after a crash can
// act on it. Carries BOTH yaml (the persisted ledger) and json (the Invoke/reverse-channel
// envelope) tags — the retag step emits both automatically, mirroring the json key.
type HolderAddr struct {
	Name string `yaml:"name,omitempty" json:"name"`

	Target string `yaml:"target,omitempty" json:"target"`

	Base string `yaml:"base,omitempty" json:"base"`

	Instance string `yaml:"instance,omitempty" json:"instance,omitempty"`

	Vm string `yaml:"vm,omitempty" json:"vm,omitempty"`
}

// #PreemptedHolder records one holder a lease stopped, its declared exclusive tokens, and its
// restore policy — so ReleaseClaimant/reconcile restart exactly what was stopped.
type PreemptedHolder struct {
	Addr HolderAddr `yaml:"addr,omitempty" json:"addr"`

	Holds []string `yaml:"holds,omitempty" json:"holds"`

	Restore string `yaml:"restore,omitempty" json:"restore"`
}

// #PreemptLease is one active resource claim — exclusive (a VM with sole use) or shared (a
// refcounted pod claim; many coexist on one token).
type PreemptLease struct {
	Claimant string `yaml:"claimant,omitempty" json:"claimant"`

	Claim HolderAddr `yaml:"claim,omitempty" json:"claim"`

	Tokens []string `yaml:"tokens,omitempty" json:"tokens"`

	Shared bool `yaml:"shared,omitempty" json:"shared,omitempty"`

	Mode string `yaml:"mode,omitempty" json:"mode,omitempty"`

	Transient bool `yaml:"transient,omitempty" json:"transient"`

	Preempted []PreemptedHolder `yaml:"preempted,omitempty" json:"preempted"`

	Created string `yaml:"created,omitempty" json:"created"`

	// owner_pid/owner_start identify the OUTERMOST process that created the lease — the liveness
	// signal a concurrent charly process's reconcile uses (leaseLive).
	OwnerPID int64 `yaml:"owner_pid,omitempty" json:"owner_pid,omitempty"`

	OwnerStart string `yaml:"owner_start,omitempty" json:"owner_start,omitempty"`
}

// #PreemptLedger is the on-disk lease set (~/.local/share/charly/preemption/leases.yml).
type PreemptLedger struct {
	Leases []PreemptLease `yaml:"leases,omitempty" json:"leases"`
}

// #HolderDescriptor is one candidate preemptible holder, pre-projected host-side.
type HolderDescriptor struct {
	Name string `yaml:"name,omitempty" json:"name"`

	Holds []string `yaml:"holds,omitempty" json:"holds"`

	Addr HolderAddr `yaml:"addr,omitempty" json:"addr"`

	Restore string `yaml:"restore,omitempty" json:"restore"`
}

// #ArbiterGatherReply is the host's projection of every RUNNING-or-not preemptible holder the
// arbiter may stop: PreemptionHolds() + holderAddrFor() + preemptEffectiveRestore() are applied
// host-side so the plugin's holdersToStop is pure config-free coordination.
type ArbiterGatherReply struct {
	Holders []HolderDescriptor `yaml:"holders,omitempty" json:"holders"`
}

// #ArbiterResourcesReply maps each GPU-BACKED arbitration token to its PCI vendor (e.g.
// "nvidia-gpu" -> "0x10de"). A token ABSENT from the map is arbitration-only (no device to flip;
// applyMode skips it, firstPoisonedToken ignores it).
type ArbiterResourcesReply struct {
	Gpu map[string]string `yaml:"gpu,omitempty" json:"gpu"`
}

// #ArbiterInvokeInput is the action-multiplexed input the in-core proxy ships to verb:arbiter.
// Each action populates only the field(s) it needs (the OTHERS stay Go zero-value); claim_addr is
// REQUIRED rather than optional because the original hand-written type's `omitempty` on a
// value-typed (non-pointer) HolderAddr field was already a no-op in encoding/json — Go's
// omitempty never elides a struct value — so marking it required here changes nothing about the
// actual wire bytes, only how honestly the schema describes them.
type ArbiterInvokeInput struct {
	Action string `yaml:"action,omitempty" json:"action"`

	Claimant string `yaml:"claimant,omitempty" json:"claimant,omitempty"`

	Tokens []string `yaml:"tokens,omitempty" json:"tokens,omitempty"`

	ClaimAddr HolderAddr `yaml:"claim_addr,omitempty" json:"claim_addr"`

	Transient bool `yaml:"transient,omitempty" json:"transient,omitempty"`

	Success bool `yaml:"success,omitempty" json:"success,omitempty"`

	Token string `yaml:"token,omitempty" json:"token,omitempty"`
}

// #ArbiterInvokeReply is the action-multiplexed reply from verb:arbiter.
type ArbiterInvokeReply struct {
	Active bool `yaml:"active,omitempty" json:"active,omitempty"`

	Bool bool `yaml:"bool,omitempty" json:"bool,omitempty"`

	Ledger *PreemptLedger `yaml:"ledger,omitempty" json:"ledger,omitempty"`

	Stranded []string `yaml:"stranded,omitempty" json:"stranded,omitempty"`

	Error string `yaml:"error,omitempty" json:"error,omitempty"`
}

// MergeConfig (config.go). CLOSED.
type BoxMerge struct {
	Auto bool `yaml:"auto,omitempty" json:"auto,omitempty"`

	MaxMB int `yaml:"max_mb,omitempty" json:"max_mb,omitempty"`

	MaxTotalMB int `yaml:"max_total_mb,omitempty" json:"max_total_mb,omitempty"`
}

// AliasConfig (config.go). CLOSED. command defaults to name when omitted.
type BoxAlias struct {
	Name string `yaml:"name,omitempty" json:"name"`

	Command string `yaml:"command,omitempty" json:"command,omitempty"`
}

// ReadinessConfig (config.go / readiness_config.go) — the `defaults.readiness:`
// bounds for the unified pollUntil readiness primitive (poll.go). CLOSED. Every
// field is a Go time.ParseDuration string; absent → the named fallback const in
// poll.go. Defaults-only (reuses the BoxConfig type), but modeled here per the
// #Box completeness invariant in this file's header. The Resolve()-time ordering
// invariants (interval <= no_progress <= absolute_cap; poll_interval_local <=
// stop_grace <= absolute_cap) are cross-field and stay in Go (validateOrdering).
type Readiness struct {
	PollIntervalLocal Duration `yaml:"poll_interval_local,omitempty" json:"poll_interval_local,omitempty"`

	PollIntervalRemote Duration `yaml:"poll_interval_remote,omitempty" json:"poll_interval_remote,omitempty"`

	PollIntervalHeavy Duration `yaml:"poll_interval_heavy,omitempty" json:"poll_interval_heavy,omitempty"`

	PerAttempt Duration `yaml:"per_attempt,omitempty" json:"per_attempt,omitempty"`

	PerAttemptHeavy Duration `yaml:"per_attempt_heavy,omitempty" json:"per_attempt_heavy,omitempty"`

	NoProgress Duration `yaml:"no_progress,omitempty" json:"no_progress,omitempty"`

	AbsoluteCap Duration `yaml:"absolute_cap,omitempty" json:"absolute_cap,omitempty"`

	StopGrace Duration `yaml:"stop_grace,omitempty" json:"stop_grace,omitempty"`
}

// base and from are mutually exclusive; neither is also valid (scratch box).
// The entity-level base⊻from mutual-exclusion is enforced in GO
// (BoxConfig.HasBaseFromConflict, surfaced by validateBoxBaseFrom in validate.go
// and resolveBase in config.go) — NOT by a trailing `& ({from?: _|_} |
// {base?: _|_})` disjunction. `cue exp gengotypes` collapses an entity-level
// top-level disjunction to an EMPTY `struct{}`, which would make spec.Box useless
// as a drop-in for BoxConfig; the plain closed struct below generates the full
// field set, and the Go rule restores the XOR. The struct stays CLOSED (no `...`)
// so an unknown key is still a typo.
type Box struct {
	Name EntityRef `yaml:"name,omitempty" json:"name,omitempty"`

	Version CalVer `yaml:"version,omitempty" json:"version,omitempty"`

	Description string `yaml:"description,omitempty" json:"description,omitempty"`

	Enabled *bool `yaml:"enabled,omitempty" json:"enabled,omitempty"`

	Base string `yaml:"base,omitempty" json:"base,omitempty"`

	From string `yaml:"from,omitempty" json:"from,omitempty"`

	BootstrapBuilderImage string `yaml:"bootstrap_builder_image,omitempty" json:"bootstrap_builder_image,omitempty"`

	Platforms []string `yaml:"platform,omitempty" json:"platform,omitempty"`

	Tag string `yaml:"tag,omitempty" json:"tag,omitempty"`

	Registry string `yaml:"registry,omitempty" json:"registry,omitempty"`

	Distro []string `yaml:"distro,omitempty" json:"distro,omitempty"`

	// BuildFormats: a scalar OR a list on the wire (#BuildFormats UnmarshalYAML
	// normalizes "rpm" → ["rpm"]); the Go field is []string. gengotypes degrades
	// the disjunction to `any`, so pin the Go shape explicitly (the typed enum is
	// a future enhancement — collapse for now).
	Build []string `yaml:"build,omitempty" json:"build,omitempty"`

	Candy []CandyRef `yaml:"candy,omitempty" json:"candy,omitempty"`

	User string `yaml:"user,omitempty" json:"user,omitempty"`

	UID *int `yaml:"uid,omitempty" json:"uid,omitempty"`

	GID *int `yaml:"gid,omitempty" json:"gid,omitempty"`

	UserPolicy string `yaml:"user_policy,omitempty" json:"user_policy,omitempty"`

	Builder map[string]string `yaml:"builder,omitempty" json:"builder,omitempty"`

	Produce []BuildType `yaml:"produce,omitempty" json:"produce,omitempty"`

	Env map[string]string `yaml:"env,omitempty" json:"env,omitempty"`

	EnvFile string `yaml:"env_file,omitempty" json:"env_file,omitempty"`

	Security *Security `yaml:"security,omitempty" json:"security,omitempty"`

	Network string `yaml:"network,omitempty" json:"network,omitempty"`

	Init string `yaml:"init,omitempty" json:"init,omitempty"`

	DataImage bool `yaml:"data_image,omitempty" json:"data_image,omitempty"`

	Bootc bool `yaml:"bootc,omitempty" json:"bootc,omitempty"`

	Readiness *Readiness `yaml:"readiness,omitempty" json:"readiness,omitempty"`

	Jobs *int `yaml:"jobs,omitempty" json:"jobs,omitempty"`

	PodmanJobs *int `yaml:"podman_jobs,omitempty" json:"podman_jobs,omitempty"`

	PodmanJobsCap *int `yaml:"podman_jobs_cap,omitempty" json:"podman_jobs_cap,omitempty"`

	ContextIgnore []string `yaml:"context_ignore,omitempty" json:"context_ignore,omitempty"`

	Cache string `yaml:"cache,omitempty" json:"cache,omitempty"`

	KeepImages *int `yaml:"keep_images,omitempty" json:"keep_images,omitempty"`

	KeepCheckRuns *int `yaml:"keep_check_runs,omitempty" json:"keep_check_runs,omitempty"`

	Merge *BoxMerge `yaml:"merge,omitempty" json:"merge,omitempty"`

	Alias []BoxAlias `yaml:"alias,omitempty" json:"alias,omitempty"`

	Plan []Step `yaml:"plan,omitempty" json:"plan,omitempty"`

	CheckLevel string `yaml:"check_level,omitempty" json:"check_level,omitempty"`

	Shell *Shell `yaml:"shell,omitempty" json:"shell,omitempty"`
}

